
(function(){const data=window.GOALOS_SITE_MAP;const state={group:'all',audience:'all',q:''};const $=s=>document.querySelector(s);const groups=['all',...new Set(data.routes.map(r=>r.group))];const audiences=['all',...new Set(data.routes.flatMap(r=>r.audience||[]))];function chipBox(sel,vals,key){const box=$(sel);box.innerHTML='';vals.forEach(v=>{const b=document.createElement('button');b.type='button';b.className='atlas-chip'+(state[key]===v?' active':'');b.textContent=v==='all'?'All':v;b.onclick=()=>{state[key]=v;chipBox(sel,vals,key);render();};box.appendChild(b);});}function matches(r){const h=(r.title+' '+r.group+' '+r.summary+' '+r.audience.join(' ')).toLowerCase();return(state.group==='all'||r.group===state.group)&&(state.audience==='all'||r.audience.includes(state.audience))&&(!state.q||h.includes(state.q));}function render(){const grid=$('#atlasGrid');grid.innerHTML='';const routes=data.routes.filter(matches);$('#atlasCount').textContent=routes.length;routes.forEach(r=>{const c=document.createElement('article');c.className='atlas-card';c.innerHTML=`<div class="atlas-meta">${r.group} · ${r.time} min · ${r.audience.join(' / ')}</div><h3>${r.title}</h3><p>${r.summary}</p><a href="${r.href}">Open page →</a>`;grid.appendChild(c);});}function journeys(){const box=$('#atlasJourneys');box.innerHTML='';data.journeys.forEach(j=>{const c=document.createElement('section');c.className='atlas-journey';c.innerHTML=`<h3>${j.title}</h3><ol>${j.steps.map(id=>{const r=data.routes.find(x=>x.id===id);return `<li><a href="${r.href}">${r.title}</a></li>`}).join('')}</ol>`;box.appendChild(c);});}function boot(){chipBox('#groupChips',groups,'group');chipBox('#audienceChips',audiences,'audience');$('#atlasSearch').oninput=e=>{state.q=e.target.value.trim().toLowerCase();render();};$('#totalPages').textContent=data.routes.length;$('#totalJourneys').textContent=data.journeys.length;journeys();render();}boot();})();
